package hash

import (
	"encoding/hex"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestHashSigned(t *testing.T) {
	txBlob := ""
	expectedHash := "7BF105CFE4EFE78ADB63FE4E03A851440551FE189FD4B51CAAD9279C9F534F0E"

	txB, err := hex.DecodeString(txBlob)
	require.NoError(t, err)

	expectedH, err := hex.DecodeString(expectedHash)
	require.NoError(t, err)

	computedH := Signed(txB)

	require.Equal(t, expectedH, computedH)
}

// TestHashSignedPrefix pins the transactionID hash prefix ('TXN\0') to the
// value defined in rippled's HashPrefix.h.
func TestHashSignedPrefix(t *testing.T) {
	// source: rippled include/xrpl/protocol/HashPrefix.h:36 (HashPrefix::transactionID)
	// Also xrpl.js packages/xrpl/src/utils/hashes/HashPrefix.ts:16 (TRANSACTION_ID = 0x54584e00).
	const want uint32 = 0x54584E00
	assert.Equal(t, want, signedPrefix)
}

// TestHashSignedVectors exercises Signed against signed-transaction blobs and
// their canonical transaction hashes gathered from xrpl.js primary-source
// fixtures.
func TestHashSignedVectors(t *testing.T) {
	tests := []struct {
		name string
		blob string
		hash string
	}{
		{
			// source: xrpl.js packages/xrpl/test/fixtures/rippled/submit.json (tx_blob + tx_json.hash)
			name: "paymentUSDBlob",
			blob: "",
			hash: "4D5D90890F8D49519E4151938601EF3D0B30B16CD6A519D9C99102C9FA77F7E0",
		},
		{
			// source: xrpl.js packages/xrpl/test/fixtures/responses/sign.json (signedTransaction + id)
			// Cross-checked in packages/xrpl/test/wallet/index.test.ts:454 (expected hash).
			name: "signNormal",
			blob: "",
			hash: "93F6C6CE73C092AA005103223F3A1F557F4C097A2943D96760F6490F04379917",
		},
		{
			// source: xrpl.js packages/xrpl/test/fixtures/responses/signAs.json (signedTransaction + id)
			// Cross-checked in packages/xrpl/test/wallet/index.test.ts:586 (expected hash).
			name: "signAs",
			blob: "",
			hash: "D8CF5FC93CFE5E131A34599AFB7CE186A5B8D1B9F069E35F4634AD3B27837E35",
		},
		{
			// source: xrpl.js packages/xrpl/test/fixtures/responses/signEscrow.json (signedTransaction + id)
			// Cross-checked in packages/xrpl/test/wallet/index.test.ts:575 (expected hash).
			name: "signEscrow",
			blob: "",
			hash: "645B7676DF057E4F5E83F970A18B3751B6813807F1030A8D2F482D02DC885106",
		},
		{
			// source: xrpl.js packages/xrpl/test/fixtures/responses/signTicket.json (signedTransaction + id)
			name: "signTicket",
			blob: "",
			hash: "0AC60B1E1F063904D9D9D0E9D03F2E9C8D41BC6FC872D5B8BF87E15BBF9669BB",
		},
		{
			// source: xrpl.js packages/xrpl/test/wallet/index.test.ts:487 (tx_blob + hash, memos tx)
			name: "memosPayment",
			blob: "",
			hash: "41B9CB78D8E18A796CDD4B0BC6FB0EA19F64C4F25FDE23049197852CAB71D10D",
		},
	}

	for _, test := range tests {
		t.Run(test.name, func(t *testing.T) {
			blob, err := hex.DecodeString(test.blob)
			require.NoError(t, err)
			want, err := hex.DecodeString(test.hash)
			require.NoError(t, err)

			assert.Equal(t, want, Signed(blob))
		})
	}
}

func TestChecksum(t *testing.T) {
	tests := []struct {
		data     string
		expected string
	}{
		{
			data:     "0053e1d2aa89ffd9b652ee438f1de36d183bcd32f1",
			expected: "5464291b",
		},
	}

	for _, test := range tests {
		b, err := hex.DecodeString(test.data)
		require.NoError(t, err)

		result := Checksum(b)
		r, err := hex.DecodeString(test.expected)
		require.NoError(t, err)

		require.Equal(t, r, result)
	}
}
